using Microsoft.AspNetCore.Identity; namespace LumiBeauty.Api.Data; public static class AdminSeeder{public static async Task SeedAsync(IServiceProvider services,IConfiguration config){using var scope=services.CreateScope();var users=scope.ServiceProvider.GetRequiredService<UserManager<IdentityUser>>();var roles=scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();var email=config["AdminSeed:Email"];var pass=config["AdminSeed:Password"];if(string.IsNullOrWhiteSpace(email)||string.IsNullOrWhiteSpace(pass)){Console.WriteLine("Admin secrets eksik.");return;}const string role="Admin";if(!await roles.RoleExistsAsync(role))await roles.CreateAsync(new IdentityRole(role));var user=await users.FindByEmailAsync(email);if(user is null){user=new IdentityUser{UserName=email,Email=email,EmailConfirmed=true};var result=await users.CreateAsync(user,pass);if(!result.Succeeded)throw new InvalidOperationException(string.Join(", ",result.Errors.Select(x=>x.Description)));}if(!await users.IsInRoleAsync(user,role))await users.AddToRoleAsync(user,role);Console.WriteLine("Admin hesabı hazır.");}}
